import sysfrom pathlib import Pathimport jsonimport joblibimport pandas as pdfrom sklearn.feature_extraction.text import TfidfVectorizerfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import (    accuracy_score,    f1_score,    classification_report,    confusion_matrix,)from sklearn.pipeline import Pipeline# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    BASELINE_MODELS_DIR,    REPORTS_DIR,    TABLE_DIR,)TEXT_COL = "full_text"LABEL_COL = "label_5d"def load_data():    train_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d.parquet")    val_df = pd.read_parquet(PROCESSED_DATA_DIR / "validation_doc_5d.parquet")    test_df = pd.read_parquet(PROCESSED_DATA_DIR / "test_doc_5d.parquet")    return train_df, val_df, test_dfdef basic_data_check(df: pd.DataFrame, split_name: str):    print(f"\n--- {split_name.upper()} ---")    print("Shape:", df.shape)    print("Label distribution:")    print(df[LABEL_COL].value_counts(dropna=False).sort_index())    print("\nSample text preview:")    print(df[[TEXT_COL, LABEL_COL]].head(2))def train_and_select_model(train_df, val_df):    candidates = [        {"max_features": 5000, "ngram_range": (1, 1), "C": 1.0},        {"max_features": 10000, "ngram_range": (1, 1), "C": 1.0},        {"max_features": 10000, "ngram_range": (1, 2), "C": 1.0},    ]    X_train = train_df[TEXT_COL].astype(str)    y_train = train_df[LABEL_COL].astype(int)    X_val = val_df[TEXT_COL].astype(str)    y_val = val_df[LABEL_COL].astype(int)    best_model = None    best_result = None    all_results = []    for i, cfg in enumerate(candidates, start=1):        print(f"\nTraining candidate {i}: {cfg}")        pipe = Pipeline([            (                "tfidf",                TfidfVectorizer(                    lowercase=True,                    stop_words="english",                    max_features=cfg["max_features"],                    ngram_range=cfg["ngram_range"],                    min_df=2,                ),            ),            (                "clf",                LogisticRegression(                    C=cfg["C"],                    max_iter=2000,                    random_state=42,                ),            ),        ])        pipe.fit(X_train, y_train)        val_pred = pipe.predict(X_val)        acc = accuracy_score(y_val, val_pred)        f1 = f1_score(y_val, val_pred)        result = {            "candidate_id": i,            "max_features": cfg["max_features"],            "ngram_range": str(cfg["ngram_range"]),            "C": cfg["C"],            "val_accuracy": acc,            "val_f1": f1,        }        all_results.append(result)        print(f"Validation Accuracy: {acc:.4f}")        print(f"Validation F1:       {f1:.4f}")        if best_result is None or f1 > best_result["val_f1"]:            best_result = result            best_model = pipe    results_df = pd.DataFrame(all_results)    return best_model, best_result, results_dfdef evaluate_on_test(model, test_df):    X_test = test_df[TEXT_COL].astype(str)    y_test = test_df[LABEL_COL].astype(int)    test_pred = model.predict(X_test)    test_acc = accuracy_score(y_test, test_pred)    test_f1 = f1_score(y_test, test_pred)    cm = confusion_matrix(y_test, test_pred)    clf_report = classification_report(y_test, test_pred, output_dict=True)    print("\n=== TEST PERFORMANCE ===")    print(f"Test Accuracy: {test_acc:.4f}")    print(f"Test F1:       {test_f1:.4f}")    print("Confusion Matrix:")    print(cm)    return {        "test_accuracy": test_acc,        "test_f1": test_f1,        "confusion_matrix": cm.tolist(),        "classification_report": clf_report,    }def extract_top_keywords(model, top_n=30):    tfidf = model.named_steps["tfidf"]    clf = model.named_steps["clf"]    feature_names = tfidf.get_feature_names_out()    coefs = clf.coef_[0]    coef_df = pd.DataFrame({        "term": feature_names,        "coef": coefs,    }).sort_values("coef")    top_negative = coef_df.head(top_n).copy()    top_positive = coef_df.tail(top_n).copy().sort_values("coef", ascending=False)    return top_positive, top_negativedef save_outputs(model, best_result, results_df, test_results, top_positive, top_negative):    BASELINE_MODELS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    model_path = BASELINE_MODELS_DIR / "tfidf_logistic_best.joblib"    report_path = REPORTS_DIR / "tfidf_logistic_results.json"    candidate_table_path = TABLE_DIR / "tfidf_logistic_validation_results.csv"    top_pos_path = TABLE_DIR / "tfidf_logistic_top_positive_terms.csv"    top_neg_path = TABLE_DIR / "tfidf_logistic_top_negative_terms.csv"    joblib.dump(model, model_path)    report_payload = {        "best_validation_result": best_result,        "test_results": test_results,    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(report_payload, f, indent=2)    results_df.to_csv(candidate_table_path, index=False)    top_positive.to_csv(top_pos_path, index=False)    top_negative.to_csv(top_neg_path, index=False)    print("\nSaved outputs:")    print(model_path)    print(report_path)    print(candidate_table_path)    print(top_pos_path)    print(top_neg_path)def main():    print("Loading document-level datasets...")    train_df, val_df, test_df = load_data()    basic_data_check(train_df, "train")    basic_data_check(val_df, "validation")    basic_data_check(test_df, "test")    print("\nSelecting best TF-IDF + Logistic model on validation set...")    best_model, best_result, results_df = train_and_select_model(train_df, val_df)    print("\nBest validation configuration:")    print(best_result)    test_results = evaluate_on_test(best_model, test_df)    print("\nExtracting top keywords...")    top_positive, top_negative = extract_top_keywords(best_model, top_n=30)    print("\nTop positive terms:")    print(top_positive.head(10))    print("\nTop negative terms:")    print(top_negative.head(10))    save_outputs(        best_model,        best_result,        results_df,        test_results,        top_positive,        top_negative,    )    print("\nDone.")if __name__ == "__main__":    main()